import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, Tuple


def decode_jwt(token: str, secret: Optional[str] = None, verify: bool = False, algorithms: Optional[list] = None) -> Tuple[bool, Dict[str, Any]]:
    """
    Decode and optionally verify a JWT token for debugging purposes.
    
    Args:
        token: The JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify the signature (default False for debugging)
        algorithms: List of allowed algorithms (default ['HS256', 'HS384', 'HS512', 'RS256'])
    
    Returns:
        Tuple of (is_valid, decoded_data)
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512']
    
    result = {
        'valid': False,
        'header': None,
        'payload': None,
        'signature': None,
        'errors': [],
        'warnings': []
    }
    
    try:
        result['header'] = jwt.get_unverified_header(token)
    except Exception as e:
        result['errors'].append(f"Failed to decode header: {str(e)}")
        return False, result
    
    try:
        options = {
            'verify_signature': verify,
            'verify_exp': verify,
            'verify_nbf': verify,
            'verify_iat': verify,
            'verify_aud': verify
        }
        
        if verify and secret:
            decoded = jwt.decode(token, secret, algorithms=algorithms, options=options)
            result['valid'] = True
        else:
            decoded = jwt.decode(token, options={'verify_signature': False})
            result['warnings'].append('Signature not verified - debugging mode')
        
        result['payload'] = decoded
        
        if 'exp' in decoded:
            exp_time = datetime.fromtimestamp(decoded['exp'])
            now = datetime.now()
            if exp_time < now:
                result['warnings'].append(f"Token expired at {exp_time}")
            else:
                result['warnings'].append(f"Token valid until {exp_time}")
        
        if 'nbf' in decoded:
            nbf_time = datetime.fromtimestamp(decoded['nbf'])
            now = datetime.now()
            if nbf_time > now:
                result['warnings'].append(f"Token not valid before {nbf_time}")
        
        if 'iat' in decoded:
            iat_time = datetime.fromtimestamp(decoded['iat'])
            result['warnings'].append(f"Token issued at {iat_time}")
        
        parts = token.split('.')
        if len(parts) == 3:
            result['signature'] = parts[2]
        
        return True, result
        
    except jwt.ExpiredSignatureError:
        result['errors'].append('Token has expired')
        try:
            result['payload'] = jwt.decode(token, options={'verify_signature': False})
        except:
            pass
        return False, result
    except jwt.InvalidSignatureError:
        result['errors'].append('Invalid signature')
        try:
            result['payload'] = jwt.decode(token, options={'verify_signature': False})
        except:
            pass
        return False, result
    except jwt.DecodeError as e:
        result['errors'].append(f'Decode error: {str(e)}')
        return False, result
    except Exception as e:
        result['errors'].append(f'Unexpected error: {str(e)}')
        return False, result


def pretty_print_jwt(token: str, secret: Optional[str] = None, verify: bool = False):
    """
    Decode and pretty print a JWT token for debugging.
    """
    is_valid, result = decode_jwt(token, secret, verify)
    
    print("=" * 80)
    print("JWT TOKEN ANALYSIS")
    print("=" * 80)
    
    if result['header']:
        print("\n--- HEADER ---")
        print(json.dumps(result['header'], indent=2))
    
    if result['payload']:
        print("\n--- PAYLOAD ---")
        print(json.dumps(result['payload'], indent=2, default=str))
    
    if result['signature']:
        print("\n--- SIGNATURE ---")
        print(f"{result['signature'][:50]}...")
    
    if result['warnings']:
        print("\n--- WARNINGS ---")
        for warning in result['warnings']:
            print(f"⚠ {warning}")
    
    if result['errors']:
        print("\n--- ERRORS ---")
        for error in result['errors']:
            print(f"✗ {error}")
    
    print("\n--- STATUS ---")
    print(f"Valid: {is_valid}")
    print("=" * 80)


def inspect_jwt_quick(token: str) -> Dict[str, Any]:
    """
    Quick inspection without verification - returns just the payload.
    """
    try:
        return jwt.decode(token, options={'verify_signature': False})
    except Exception as e:
        return {'error': str(e)}


